+func TestAsyncCheckpointPushDrainsBeforeFinalSnapshot(t *testing.T) {
+	ctx := context.Background()
+	dir := t.TempDir()
+	repo := filepath.Join(dir, "repo")
+	remote := filepath.Join(dir, "remote.git")
+	config := filepath.Join(dir, "backup.json")
